import React, { useState } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const BrowseCars = () => {
  const [filter, setFilter] = useState('all');
  const [price, setPrice] = useState('');
  const [seats, setSeats] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const cars = [
    {
      id: 1,
      name: 'Toyota Camry',
      type: 'sedan',
      price: 3500,
      seats: 5,
      image: 'https://i.imgur.com/70MJRvL.png'
    },
    {
      id: 2,
      name: 'Toyota Fortuner',
      type: 'suv',
      price: 3500,
      seats: 7,
      image: 'https://i.imgur.com/1oZxIq7.png'
    },
    {
      id: 3,
      name: 'Toyota Wigo',
      type: 'sedan',
      price: 1500,
      seats: 5,
      image: 'https://i.imgur.com/d8xwD0J.png'
    },
    {
      id: 4,
      name: 'Toyota Vios',
      type: 'sedan',
      price: 1900,
      seats: 5,
      image: 'https://i.imgur.com/Im0UTUI.png',
      favorite: true
    },
    {
      id: 5,
      name: 'Toyota HiAce Van',
      type: 'van',
      price: 4000,
      seats: 12,
      image: 'https://i.imgur.com/KnAvru6.png'
    },
    {
      id: 6,
      name: 'Toyota Hilux',
      type: 'suv',
      price: 2500,
      seats: 5,
      image: 'https://i.imgur.com/9Jkyyo6.png'
    }
  ];

  const handleFilterClick = (filterType) => {
    setFilter(filterType);
  };

  const handleSearch = (e) => {
    e.preventDefault();
    // Search logic handled by React state
  };

  const filteredCars = cars.filter(car => {
    const typeMatch = filter === 'all' || car.type === filter;
    const priceMatch = !price || car.price <= parseFloat(price);
    const seatsMatch = !seats || car.seats >= parseInt(seats);
    return typeMatch && priceMatch && seatsMatch;
  });

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <h2 style={styles.heading}>Browse Cars</h2>

        <form style={styles.filterForm} onSubmit={handleSearch}>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'all' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('all')}
          >
            All
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'sedan' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('sedan')}
          >
            Sedan
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'suv' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('suv')}
          >
            SUV
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'luxury' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('luxury')}
          >
            Luxury
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'van' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('van')}
          >
            VAN
          </button>
          <input 
            type="text" 
            placeholder="Price" 
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            style={styles.input}
          />
          <input 
            type="text" 
            placeholder="Seats" 
            value={seats}
            onChange={(e) => setSeats(e.target.value)}
            style={styles.input}
          />
          <input 
            type="date" 
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
            style={styles.input}
          />
          <input 
            type="date" 
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
            style={styles.input}
          />
          <input type="submit" value="Search" style={styles.submitBtn} />
        </form>

        <div style={styles.carsContainer}>
          {filteredCars.length === 0 ? (
            <div style={styles.noCarsMessage}>
              There is no available cars
            </div>
          ) : (
            filteredCars.map(car => (
              <div key={car.id} style={styles.carCard}>
                {car.favorite && <span style={styles.heartIcon}>♥</span>}
                <img src={car.image} alt={car.name} style={styles.carImage} />
                <h3 style={styles.carName}>{car.name}</h3>
                <div style={styles.price}>
